class Board:
    def __init__(self):
        self.initialize()

    def initialize(self):
        # Initialize the board with pieces
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.setup_pieces()

    def setup_pieces(self):
        # Set up the initial pieces
        colors = ['R', 'B']  # Red and Black pieces
        start_positions = [(0, 1), (0, 3), (0, 5), (0, 7),
                            (1, 0), (1, 2), (1, 4), (1, 6),
                            (2, 1), (2, 3), (2, 5), (2, 7)]
        for pos in start_positions:
            self.board[pos[0]][pos[1]] = colors[0]
        for row in range(3, 5):
            for col in range(8):
                if (row + col) % 2 == 0:
                    self.board[row][col] = ' '

    def draw_board(self):
        print("   a b c d e f g h")
        for i in range(8):
            row = f"{i+1} "
            for j in range(8):
                if (i + j) % 2 == 0:
                    piece = self.board[i][j]
                    row += "| " + piece + " |"
                else:
                    row += "|   |"
            print(row)

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def move_piece(self, start_pos, end_pos):
        piece = self.get_piece(start_pos)
        if piece != ' ' and (end_pos[0] - start_pos[0], end_pos[1] - start_pos[1]) in [(1, 1), (-1, -1)]:
            self.board[start_pos[0]][start_pos[1]] = ' '
            self.board[end_pos[0]][end_pos[1]] = piece
        else:
            raise ValueError("Invalid move")

    def king_piece(self, position):
        if position[0] == 0 and self.board[position[0]][position[1]] == 'B':
            self.board[position[0]][position[1]] = 'b'
        elif position[0] == 7 and self.board[position[0]][position[1]] == 'R':
            self.board[position[0]][position[1]] = 'r'

    def is_valid_move(self, start_pos, end_pos):
        piece = self.get_piece(start_pos)
        if piece == ' ':
            return False
        dx, dy = end_pos[0] - start_pos[0], end_pos[1] - start_pos[1]
        if abs(dx) != 2 or abs(dy) != 2:
            return False
        mid_pos = ((start_pos[0] + end_pos[0]) // 2, (start_pos[1] + end_pos[1]) // 2)
        mid_piece = self.get_piece(mid_pos)
        if mid_piece == ' ' or mid_piece.isupper() == piece.isupper():
            return False
        self.move_piece(start_pos, end_pos)
        for i in range(8):
            for j in range(8):
                if self.board[i][j].islower() and (i - j) % 2 == 0:
                    capture = True
                    for d in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                        next_pos = (i + 2 * d[0], j + 2 * d[1])
                        if 0 <= next_pos[0] < 8 and 0 <= next_pos[1] < 8 and self.get_piece(next_pos) == ' ':
                            capture = False
                            break
                    if capture:
                        self.move_piece(mid_pos, end_pos)
                        return True
        self.move_piece(mid_pos, start_pos)
        return False
