class Game:
    def __init__(self):
        self.board = Board()
        self.players = ['R', 'B']
        self.current_player = 0

    def switch_turn(self):
        self.current_player = (self.current_player + 1) % len(self.players)

    def check_winner(self):
        if not self.players[0].has_pieces():
            return "Player B wins"
        elif not self.players[1].has_pieces():
            return "Player R wins"
        else:
            return None

    def make_move(self, start_pos, end_pos):
        try:
            self.board.move_piece(start_pos, end_pos)
            if (end_pos[0] - start_pos[0]) == 2 or (end_pos[0] - start_pos[0]) == -2:
                self.board.king_piece(end_pos)
            return True
        except ValueError as e:
            print(e)
            return False
