from game import Game

def run():
    game = Game()
    while True:
        game.board.draw_board()
        start_pos = input(f"Player {game.players[game.current_player]}, enter start position (e.g., 2a): ")
        end_pos = input(f"Player {game.players[game.current_player]}, enter end position (e.g., 4b): ")
        if not game.make_move((int(start_pos[0]) - 1, ord(start_pos[1]) - 97), (int(end_pos[0]) - 1, ord(end_pos[1]) - 97)):
            continue
        result = game.check_winner()
        if result:
            print(result)
            break
        game.switch_turn()

if __name__ == "__main__":
    run()
